import React, { useMemo, useState } from 'react'
import { format, formatISO, parseISO, nextMonday } from 'date-fns'
import { TW_COLOR_CYCLE } from '/src/color'
import classNames from 'classnames'
import MinHeap from '/src/data-structures/minheap'
import { holidaysByWeek } from '/src/date-helpers'
import { Button, Dialog, Textbox, Tooltip } from '/src/components'

const WEEK_WIDTH = 600
const getTasksByDate = (projects, maxCapacity) => {
  let tasksByDate = {}
  for (const project of projects) {
    if (!project.tasks) {
      continue
    }
    const projectTasks = project.tasks.flatMap((task) => {
      if (!task.isCoarse) {
        return task
      }
      const taskName = task.name ?? `Task ID ${task.id}`
      const { averageTaskEstimate = 3, idealDays = 10 } = task
      const totalTaskSize = idealDays * maxCapacity
      const nTasks = Math.floor(totalTaskSize / averageTaskEstimate)
      const splitTasks = []
      for (let i = 0; i < nTasks; i++) {
        splitTasks.push({
          ...task,
          id: `${task.id}-${i}`,
          name: `${taskName} (${i + 1})`,
          isCoarse: false,
          estimate: averageTaskEstimate,
        })
      }
      const remainingEstimate = totalTaskSize - nTasks * averageTaskEstimate
      if (remainingEstimate > 0) {
        splitTasks.push({
          ...task,
          id: `${task.id}-${nTasks}`,
          name: `${taskName} - Task ${nTasks + 1})`,
          isCoarse: false,
          estimate: remainingEstimate,
        })
      }
      return splitTasks
    })
    projectTasks.sort(({ estimate: estimateA = 1 }, { estimate: estimateB = 1 }) => estimateA - estimateB)
    for (const task of projectTasks ?? []) {
      tasksByDate[task.startDate] = tasksByDate[task.startDate] || []
      tasksByDate[task.startDate].push({ project, task })
    }
  }
  return tasksByDate
}

const getProjectsPriorityMap = (projects) => Object.fromEntries(projects.map(({ id }, index) => [id, index]))

const compareTaskByDateEntry = ([dateA], [dateB]) => {
  if (dateA === dateB) {
    return 0
  }
  return dateA > dateB ? 1 : -1
}

const mergeTasks = (projectPriorityMap, tasksA, tasksB) => {
  const result = tasksA.concat(tasksB)
  result.sort(
    ({ project: projectA }, { project: projectB }) => projectPriorityMap[projectB.id] - projectPriorityMap[projectA.id]
  )
  return result
}

const getCapacityDelta = (memberCapacity, taskCapacity = 1) => ({
  taskEstimateRemaining: Math.max(0, taskCapacity - memberCapacity),
  capacity: Math.max(0, memberCapacity - taskCapacity),
})

const getInitWeeklyWork = (teamMembers, previousWeek = {}, capacityOverrides = { all: 0 }) =>
  teamMembers.map((member) => {
    const { taskEstimateRemaining = 0, tasks = [] } = previousWeek[member.id] ?? {}

    const lastTask = tasks[tasks.length - 1]

    const memberCapacity = member.capacity ?? 3
    const adjustedWeeklyCapacity =
      memberCapacity * Math.max(0, 5 - capacityOverrides.all + (capacityOverrides[member.id] ?? 0))
    return {
      memberId: member.id,
      tasks: taskEstimateRemaining > 0 && lastTask ? [lastTask] : [],
      adjustedWeeklyCapacity,
      ...getCapacityDelta(adjustedWeeklyCapacity, taskEstimateRemaining),
    }
  })

const hasSpillover = (weeklyWork) => {
  for (const memberWork of weeklyWork) {
    if (memberWork.capacity === 0 && memberWork.taskEstimateRemaining > 0) {
      return true
    }
  }
  return false
}

const getWeeklyTaskAssignment = (teamMembers, tasksTodo, previousWeek = {}, capacityOverrides = { all: 0 }) => {
  let weeklyWork = getInitWeeklyWork(teamMembers, previousWeek, capacityOverrides)
  let workHeap = new MinHeap()
  for (const memberWork of weeklyWork) {
    if (memberWork.capacity === 0) {
      continue
    }
    workHeap.insert(-memberWork.capacity, memberWork)
  }

  let remainingTodos = [...tasksTodo]
  while (!workHeap.isEmpty() && remainingTodos.length) {
    const memberWork = workHeap.remove()
    const taskTodo = remainingTodos.pop()

    Object.assign(memberWork, getCapacityDelta(memberWork.capacity, taskTodo.task.estimate))
    memberWork.tasks.push(taskTodo)
    if (memberWork.capacity) {
      workHeap.insert(-memberWork.capacity, memberWork)
    }
  }
  return [
    Object.fromEntries(weeklyWork.map((memberWork) => [memberWork.memberId, memberWork])),
    remainingTodos,
    hasSpillover(weeklyWork),
  ]
}

export const GanttChart = ({ projects, teamMembers, onChangeCapacityAdjustment }) => {
  if (teamMembers.length === 0) {
    return null
  }
  const maxCapacity = useMemo(() => Math.max(...teamMembers.map(({ capacity }) => capacity ?? 3)), [teamMembers])
  const maxWeeklyCapacity = 5 * maxCapacity

  const [weeklyTasks, projectPriorityMap] = useMemo(() => {
    let tasksByDate = getTasksByDate(projects, maxCapacity)
    let weeklyTasks = Object.entries(tasksByDate)
    weeklyTasks.sort(compareTaskByDateEntry)
    return [weeklyTasks, getProjectsPriorityMap(projects)]
  }, [projects, maxCapacity])

  const ganttData = useMemo(() => {
    let weeklyTasksIter = 0
    let tasksTodo = []
    let ganttData = []
    let week = null
    let hasSpillover = false
    while (tasksTodo.length || weeklyTasksIter < weeklyTasks.length || hasSpillover) {
      let [pendingTasksWeek, pendingTasks] = weeklyTasks[weeklyTasksIter] ?? [undefined, []]
      week = week === null ? parseISO(pendingTasksWeek) : nextMonday(week)

      const weekStr = formatISO(week, { representation: 'date' })

      if (weekStr === pendingTasksWeek) {
        weeklyTasksIter++
        tasksTodo = mergeTasks(projectPriorityMap, tasksTodo, pendingTasks)
      }

      let weeklyWork
      ;[weeklyWork, tasksTodo, hasSpillover] = getWeeklyTaskAssignment(
        teamMembers,
        tasksTodo,
        ganttData[ganttData.length - 1]?.[1],
        {
          all: holidaysByWeek.ca.on[weekStr]?.length ?? 0,
          ...Object.fromEntries(
            teamMembers.map(({ id, capacityAdjustments }) => [id, capacityAdjustments?.[weekStr]?.adjustment ?? 0])
          ),
        }
      )
      ganttData.push([week, weeklyWork])
    }
    return ganttData
  }, [weeklyTasks, teamMembers])

  const [capacityAdjustmentDate, setCapacityAdjustmentDate] = useState(null)

  return (
    <>
      <div className="w-full flex">
        <div className="flex flex-col gap-y-4 pb-4">
          <div className="text-center py-4">
            <div className="invisible">
              <div className="font-bold text-sm uppercase ">0</div>
              <div className="">0</div>
              <Button variant="contained" size="sm" className="mx-auto mt-2">
                Adjust Capacities
              </Button>
            </div>
          </div>
          {teamMembers.map((member, memberIndex) => (
            <div key={member.id} className="px-4 relative whitespace-nowrap">
              {member.name?.length ? member.name : `IC #${memberIndex + 1}`}
              <div className="flex absolute inset-y-0 left-full bg-neutral-50">
                {ganttData.map(([_, assignedTasks], weeklyWorkIndex) => {
                  const memberWork = assignedTasks[member.id]
                  const adjustedCapacityFill =
                    Math.max(maxWeeklyCapacity - memberWork.adjustedWeeklyCapacity, 0) / maxWeeklyCapacity
                  return (
                    <div key={weeklyWorkIndex} className="border-l flex justify-start" style={{ width: WEEK_WIDTH }}>
                      {memberWork.tasks.map(({ project, task }, index) => {
                        const projectColor = TW_COLOR_CYCLE[project.id % TW_COLOR_CYCLE.length].join(' ')

                        const prevTaskEstimateRemaining =
                          ganttData[weeklyWorkIndex - 1]?.[1]?.[member.id]?.taskEstimateRemaining ?? 0

                        const isSpilloverTask = index === 0 && prevTaskEstimateRemaining > 0

                        const isTaskCompleted =
                          index !== memberWork.tasks.length - 1 || memberWork.taskEstimateRemaining === 0

                        const taskName = task.name ?? `Task ID ${task.id}`

                        return (
                          <div key={task.id} className="flex items-center">
                            <Tooltip delayDuration={100}>
                              <Tooltip.Trigger asChild>
                                <div
                                  style={{
                                    width:
                                      (WEEK_WIDTH *
                                        Math.min(
                                          memberWork.adjustedWeeklyCapacity,
                                          isSpilloverTask
                                            ? prevTaskEstimateRemaining
                                            : task.estimate - (!isTaskCompleted ? memberWork.taskEstimateRemaining : 0)
                                        )) /
                                      maxWeeklyCapacity,
                                  }}
                                  className={classNames('h-full', {
                                    'pl-px': !isSpilloverTask,
                                    'pr-px': isTaskCompleted,
                                  })}
                                >
                                  <div
                                    className={classNames('px-2 h-full flex items-center', projectColor, {
                                      'rounded-l-lg': !isSpilloverTask,
                                      'rounded-r-lg': isTaskCompleted,
                                    })}
                                  >
                                    <div className="w-full overflow-hidden whitespace-nowrap text-ellipsis text-sm">
                                      {!isSpilloverTask && taskName}
                                    </div>
                                  </div>
                                </div>
                              </Tooltip.Trigger>
                              <Tooltip.Content className="bg-primary-700 text-white" side="top">
                                {taskName}
                                <Tooltip.Arrow className="fill-primary-700" side="top" />
                              </Tooltip.Content>
                            </Tooltip>
                          </div>
                        )
                      })}
                      {adjustedCapacityFill > 0 && (
                        <Tooltip delayDuration={100}>
                          <Tooltip.Trigger asChild>
                            <div
                              className="ml-auto px-px h-full flex items-center"
                              style={{ width: WEEK_WIDTH * adjustedCapacityFill }}
                            >
                              <div className="border border-dashed bg-pink-100 border-pink-600 h-full w-full" />
                            </div>
                          </Tooltip.Trigger>
                          <Tooltip.Content className="bg-primary-700 text-white w-64" side="top">
                            Capacity reduction due to holidays, vacation, or lower member capacity compared to the
                            highest capacity member.
                            <Tooltip.Arrow className="fill-primary-700" />
                          </Tooltip.Content>
                        </Tooltip>
                      )}
                    </div>
                  )
                })}
              </div>
            </div>
          ))}
        </div>
        {ganttData.map(([weekDate], i) => (
          <div key={i} className="text-center py-4 border-l flex-none" style={{ width: WEEK_WIDTH }}>
            <div className="font-bold text-sm uppercase">Week {i + 1}</div>
            <div>{format(weekDate, 'PP')}</div>
            <Button
              variant="contained"
              size="sm"
              className="mx-auto mt-2"
              onClick={() => setCapacityAdjustmentDate(weekDate)}
            >
              Adjust Capacities
            </Button>
          </div>
        ))}
      </div>
      <Dialog open={capacityAdjustmentDate !== null} onClose={() => setCapacityAdjustmentDate(null)}>
        <Dialog.Overlay>
          <Dialog.Content className="p-6 w-2xl">
            <Dialog.Title className="mb-8">
              Adjust team capacity for the week of {capacityAdjustmentDate && format(capacityAdjustmentDate, 'PP')}
            </Dialog.Title>
            <div className="grid grid-cols-5 gap-4 w-full items-center">
              {capacityAdjustmentDate &&
                teamMembers.map((member, memberIndex) => {
                  const weekStr = formatISO(capacityAdjustmentDate, { representation: 'date' })
                  const { adjustment = 0, note = '' } = member.capacityAdjustments?.[weekStr] ?? {}
                  return (
                    <>
                      <div className="col-span-1">
                        {member.name?.length ? (
                          member.name
                        ) : (
                          <>
                            IC {'#'}
                            {memberIndex + 1}
                          </>
                        )}{' '}
                      </div>
                      <Textbox
                        inputProps={{ className: 'text-right w-16' }}
                        className="text-right py-1 col-span-2"
                        type="number"
                        step={0.5}
                        suffix="Change in capacity days"
                        value={adjustment}
                        onChange={(e) => {
                          onChangeCapacityAdjustment(memberIndex, weekStr, 'adjustment', parseFloat(e.target.value))
                        }}
                      />
                      <Textbox
                        className="py-1 col-span-2"
                        prefix="Note:"
                        value={note}
                        onChange={(e) => {
                          onChangeCapacityAdjustment(memberIndex, weekStr, 'note', e.target.value)
                        }}
                      />
                    </>
                  )
                })}
            </div>
          </Dialog.Content>
        </Dialog.Overlay>
      </Dialog>
    </>
  )
}
